```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source_buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> adaptor(source_buffer);

    // Check if the requested bytes_to_read is within the available data in the buffer_adaptor
    if (bytes_to_read > (adaptor.write_ - adaptor.read_)) {
        HEXI_THROW(std::runtime_error("Requested to read more data than available in buffer"));
    }

    // Create a destination buffer with the appropriate size
    std::vector<uint8_t> destination(bytes_to_read);

    // Use the read function of buffer_adaptor to copy data to the destination buffer
    adaptor.read(destination.data(), bytes_to_read);

    // Return the read data
    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer_adaptor object from the dest_buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(dest_buffer);

    // Check if there is enough space in the buffer_adaptor to write the source_data
    if (source_data.size() > adaptor.free()) {
        HEXI_THROW(std::runtime_error("Insufficient space in buffer for write operation"));
    }

    // Use the write function of buffer_adaptor to write the source_data
    adaptor.write(source_data.data(), source_data.size());
}
```

