#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Create buffer_adaptor object and get read pointer
    hexi::buffer_adaptor<const std::vector<uint8_t>, false> adaptor(buffer);
    return adaptor.read_ptr();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Create buffer_adaptor object and get write pointer
    hexi::buffer_adaptor<std::vector<uint8_t>, false> adaptor(buffer);
    return adaptor.write_ptr();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Create buffer_adaptor object
    hexi::buffer_adaptor<const std::vector<uint8_t>, false> adaptor(buffer);

    // Calculate readable size (write_ - read_)
    size_t readable_size = buffer.size(); // Since read_=0 and write_=buffer.size() from constructor

    // Calculate free space (buffer.size() - write_)
    size_t free_space = 0; // Since write_ = buffer.size() from constructor

    return {readable_size, free_space};
}
```

**Explanation:**

1. **get_read_pointer**: Creates a `buffer_adaptor` object from the input buffer and calls `read_ptr()` which returns `buffer_.data() + read_`. Since the constructor initializes `read_ = 0`, this effectively returns the start of the buffer.

2. **get_write_pointer**: Creates a `buffer_adaptor` object and calls `write_ptr()` which returns `buffer_.data() + write_`. The constructor initializes `write_ = buffer.size()`, so this returns a pointer to the end of the buffer (ready for writing).

3. **check_buffer_space**: 
   - Creates a `buffer_adaptor` object
   - Calculates readable size as `write_ - read_` (which equals `buffer.size() - 0 = buffer.size()`)
   - Calculates free space as `buffer.size() - write_` (which equals `buffer.size() - buffer.size() = 0`)
   - Returns both values in the `BufferInfo` struct

