struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input span
    // Note: Need to create a non-const copy since buffer_adaptor expects non-const reference
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(buffer_copy);

    DataResult result;

    // Use buffer_adaptor's preview function to read the first byte without advancing read pointer
    result.data_type = adaptor.preview<uint8_t>();

    // Calculate the total required bytes: item_count (uint32_t) + (item_count * sizeof(item))
    // First, we need to read the item_count to calculate total size
    uint32_t item_count = 0;

    // Create binary_stream to read the item_count
    hexi::binary_stream stream(adaptor);
    stream >> item_count;

    // Calculate total required bytes
    size_t total_required_bytes = sizeof(uint32_t) + (item_count * sizeof(uint32_t));

    // Check if the buffer has enough data using buffer_adaptor's size() function
    if (adaptor.size() < total_required_bytes) {
        // Not enough data, return empty result
        return result;
    }

    // Read the items based on the data type
    if (result.data_type == 0) { // integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value;
            stream >> value;
            result.int_items[i] = value;
