std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Ensure we don't read more than available data
    size_t bytes_to_read_clamped = std::min(bytes_to_read, buffer.size());

    std::vector<uint8_t> result(bytes_to_read_clamped);
    buffer.read(result.data(), bytes_to_read_clamped);

    return result;
}

