    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Update the header with the correct value
    buffer.write(&header_value, sizeof(header_value));

    // Restore the position after updating the header
    buffer.write_seek(hexi::buffer_seek::sk_absolute, buffer.size());
