    // Reset reader position to beginning for decoding
    // Note: In a real implementation, we'd need to seek to beginning
    // For this example, we'll create a new reader on the same buffer
    hexi::pmc::binary_stream_reader reader2(adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader2);

    // Verify roundtrip correctness
    bool success = (original_value == decoded_value);

    if (!success) {
        // Additional verification: check that we wrote something
        assert(bytes_written > 0);
    }

    return success;
}
