struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Create buffer to hold serialized data
    std::vector<uint8_t> buffer;

    // Create binary_stream object for writing
    hexi::binary_stream<std::vector<uint8_t>> stream(buffer);

    // Convert message_id from native to big-endian and write
    uint32_t big_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(&big_message_id, sizeof(big_message_id));

    // Convert and write data_values vector
    std::vector<uint16_t> big_data_values;
    big_data_values.reserve(packet.data_values.size());
    for (const auto& value : packet.data_values) {
        big_data_values.push_back(hexi::endian::native_to_big(value));
    }
    stream.write_container(big_data_values);

    // Convert checksum from native to big-endian and write
    uint32_t big_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(&big_checksum, sizeof(big_checksum));

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;

    // Create binary_stream object for reading
    hexi::binary_stream<const std::span<const uint8_t>> stream(buffer);

    // Read message_id and convert from big-endian to native
    uint32_t message_id;
    stream.read(&message_id, sizeof(message_id));
    packet.message_id = hexi::endian::big_to_native(message_id);

    // Read data_values count
    uint32_t data_count;
    stream.read(&data_count, sizeof(data_count));
    data_count = hexi::endian::big_to_native(data_count);

    // Read data_values vector
    packet.data_values.resize(data_count);
    stream.read_container(packet.data_values);

    // Convert each element from big-endian to native
    for (auto& value : packet.data_values) {
        value = hexi::endian::big_to_native(value);
    }

    // Read checksum and convert from big-endian to native
    uint32_t checksum;
    stream.read(&checksum, sizeof(checksum));
    packet.checksum = hexi::endian::big_to_native(checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
