struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) {
        if constexpr (std::is_same_v<std::decay_t<decltype(adaptor)>, hexi::stream_write_adaptor>) {
            // Serialization (writing)
            adaptor.write(sensor_id);

            for (auto& temp : temperatures) {
                auto converted = hexi::endian::conditional_reverse(
                    temp, std::endian::native, std::endian::little
                );
                adaptor.write(converted);
            }

            auto converted_pressure = hexi::endian::conditional_reverse(
                pressure, std::endian::native, std::endian::little
            );
            adaptor.write(converted_pressure);
        } else {
            // Deserialization (reading)
            adaptor.read(sensor_id);

            // Read temperatures
            for (size_t i = 0; i < temperatures.size(); ++i) {
                float temp;
                adaptor.read(temp);
                hexi::endian::little_to_native_inplace(temp);
                temperatures[i] = temp;
            }

            double p;
            adaptor.read(p);
            hexi::endian::little_to_native_inplace(p);
            pressure = p;
        }
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer, hexi::init_empty_t{});
    hexi::binary_stream stream(adaptor);

    stream.serialise(data);
    return buffer;
}

