    MeasurementData data;

    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(
        std::vector<uint8_t>(buffer.begin(), buffer.end())));
    hexi::binary_stream stream(adaptor);

    stream.deserialise(data);
    return data;
